mapper.select:
SELECT t.id, t.log_type AS logType, t.title, t.content, t.method, t.request_method AS requestMethod, t.ip, t.status, t.cost_time AS costTime, t.create_time AS createTime FROM ( SELECT id, 'LOGIN' AS log_type, username AS title, msg AS content, NULL AS method, NULL AS request_method, ip, status, NULL AS cost_time, create_time FROM sys_login_log UNION ALL SELECT id, 'OPER' AS log_type, module AS title, request_url AS content, method, request_method, NULL AS ip, status, cost_time, create_time FROM sys_oper_log ) t
AND t.log_type = #{query.logType}
AND t.status = #{query.status}
AND ( t.title LIKE CONCAT('%', #{query.keyword}, '%') OR t.content LIKE CONCAT('%', #{query.keyword}, '%') OR t.method LIKE CONCAT('%', #{query.keyword}, '%') OR t.request_method LIKE CONCAT('%', #{query.keyword}, '%') OR t.ip LIKE CONCAT('%', #{query.keyword}, '%') )
ORDER BY t.create_time DESC
